#include <stdio.h>
#include <string.h>

int beats(char a, char b) {
    // returns 1 if a beats b, -1 if b beats a, 0 if tie
    if (a == b) return 0;
    if (a == 'R' && b == 'S') return 1;
    if (a == 'S' && b == 'P') return 1;
    if (a == 'P' && b == 'R') return 1;
    return -1;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        static char s[500005];
        scanf("%s", s);
        static char ans[500005];
        char curMove = s[N-1];
        ans[N-1] = curMove;
        for (int i = N-2; i >= 0; --i) {
            int r = beats(s[i], curMove);
            if (r >= 0) { // s[i] beats or ties (tie -> lower index wins)
                curMove = s[i];
            }
            ans[i] = curMove;
        }
        ans[N] = '\0';
        printf("%s\n", ans);
    }
    return 0;
}

