import java.io.*;
import java.util.*;

public class Main {
    private static int beats(char a, char b) {
        if (a == b) return 0;
        if (a == 'R' && b == 'S') return 1;
        if (a == 'S' && b == 'P') return 1;
        if (a == 'P' && b == 'R') return 1;
        return -1;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String S = br.readLine().trim();
            char[] ans = new char[N];
            char cur = S.charAt(N-1);
            ans[N-1] = cur;
            for (int i = N-2; i >= 0; --i) {
                int r = beats(S.charAt(i), cur);
                if (r >= 0) cur = S.charAt(i);
                ans[i] = cur;
            }
            out.append(new String(ans)).append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def beats(a, b):
    if a == b:
        return 0
    if a == 'R' and b == 'S':
        return 1
    if a == 'S' and b == 'P':
        return 1
    if a == 'P' and b == 'R':
        return 1
    return -1

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        S = next(it).strip()
        ans = [''] * N
        cur = S[-1]
        ans[N-1] = cur
        for i in range(N-2, -1, -1):
            if beats(S[i], cur) >= 0:
                cur = S[i]
            ans[i] = cur
        out_lines.append(''.join(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

